const MONGO_URI = `mongodb+srv://${dbUser}:${dbPass}@project.kjzooku.mongodb.net/codealpha_store?appName=Project`;

mongoose.connect(MONGO_URI)
  .then(() => console.log('✅ Connected to Atlas for seeding...'))
